function BillSplitter() {
  const [total, setTotal] = React.useState(120);
  const [people, setPeople] = React.useState(4);
  const [tip, setTip] = React.useState(18);

  const tipAmount = total * (tip / 100);
  const grandTotal = total + tipAmount;
  const perPerson = grandTotal / people;

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#ffffff', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column', color: '#1e293b' }}>
      <h2 style={{ margin: '0 0 16px', fontSize: 18 }}>Bill Splitter</h2>
      <label style={{ fontSize: 13, marginBottom: 4, fontWeight: 500 }}>Bill Total</label>
      <input type="number" value={total} onChange={e => setTotal(Number(e.target.value))} style={{ marginBottom: 12, padding: 8, borderRadius: 6, border: '1px solid #cbd5e1', fontSize: 14 }} />
      <label style={{ fontSize: 13, marginBottom: 4, fontWeight: 500 }}>People</label>
      <input type="number" value={people} onChange={e => setPeople(Number(e.target.value))} style={{ marginBottom: 12, padding: 8, borderRadius: 6, border: '1px solid #cbd5e1', fontSize: 14 }} />
      <label style={{ fontSize: 13, marginBottom: 4, fontWeight: 500 }}>Tip {tip}%</label>
      <input type="range" min="0" max="50" value={tip} onChange={e => setTip(Number(e.target.value))} style={{ marginBottom: 16 }} />
      <div style={{ background: '#f1f5f9', borderRadius: 8, padding: 12, marginTop: 'auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, marginBottom: 4 }}>
          <span>Tip:</span><span>${tipAmount.toFixed(2)}</span>
        </div>
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, marginBottom: 8 }}>
          <span>Total:</span><span>${grandTotal.toFixed(2)}</span>
        </div>
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 18, fontWeight: 700, color: '#059669' }}>
          <span>Each pays:</span><span>${perPerson.toFixed(2)}</span>
        </div>
      </div>
    </div>
  );
}
render(<BillSplitter/>);
